<?php
 namespace League\CommonMark\Extension\TableOfContents; use League\CommonMark\ConfigurableEnvironmentInterface; use League\CommonMark\Event\DocumentParsedEvent; use League\CommonMark\Extension\ExtensionInterface; use League\CommonMark\Extension\TableOfContents\Node\TableOfContentsPlaceholder; final class TableOfContentsExtension implements ExtensionInterface { public function register(ConfigurableEnvironmentInterface $environment): void { $environment->addEventListener(DocumentParsedEvent::class, [new TableOfContentsBuilder(), 'onDocumentParsed'], -150); if ($environment->getConfig('table_of_contents/position') === TableOfContentsBuilder::POSITION_PLACEHOLDER) { $environment->addBlockParser(new TableOfContentsPlaceholderParser(), 200); $environment->addBlockRenderer(TableOfContentsPlaceholder::class, new TableOfContentsPlaceholderRenderer()); } } } 